using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_WithItems_SetsPageIndex()
        {
            // Arrange
            var items = new List<int> { 1, 2, 3 };

            // Act
            var list = new PaginatedList<int>(items, 10, 2, 3);

            // Assert
            Assert.AreEqual(2, list.PageIndex);
        }

        [TestMethod]
        public void Constructor_WithItems_CalculatesTotalPagesCorrectly()
        {
            // Arrange
            var items = new List<int> { 1, 2, 3 };

            // Act
            var list = new PaginatedList<int>(items, 10, 1, 3);

            // Assert
            Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
        }

        [TestMethod]
        [DataRow(10, 5, 2, DisplayName = "10 items, 5 per page = 2 pages")]
        [DataRow(11, 5, 3, DisplayName = "11 items, 5 per page = 3 pages")]
        [DataRow(1, 10, 1, DisplayName = "1 item, 10 per page = 1 page")]
        [DataRow(0, 10, 0, DisplayName = "0 items, 10 per page = 0 pages")]
        public void Constructor_VariousCounts_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
        {
            // Act
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

            // Assert
            Assert.AreEqual(expectedTotalPages, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_AddsAllItemsToList()
        {
            // Arrange
            var items = new List<string> { "a", "b", "c" };

            // Act
            var list = new PaginatedList<string>(items, 20, 1, 5);

            // Assert
            Assert.AreEqual(3, list.Count);
            Assert.AreEqual("a", list[0]);
            Assert.AreEqual("b", list[1]);
            Assert.AreEqual("c", list[2]);
        }

        [TestMethod]
        public void HasPreviousPage_WhenPageIndexIsOne_ReturnsFalse()
        {
            // Arrange
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

            // Assert
            Assert.IsFalse(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_WhenPageIndexIsGreaterThanOne_ReturnsTrue()
        {
            // Arrange
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

            // Assert
            Assert.IsTrue(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasNextPage_WhenOnLastPage_ReturnsFalse()
        {
            // Arrange - TotalPages = ceil(10/5) = 2, PageIndex = 2
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

            // Assert
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_WhenNotOnLastPage_ReturnsTrue()
        {
            // Arrange - TotalPages = ceil(10/5) = 2, PageIndex = 1
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

            // Assert
            Assert.IsTrue(list.HasNextPage);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPageOfItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 5);

            // Assert
            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(4, result.TotalPages);
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(6, result[0]);
            Assert.AreEqual(10, result[4]);
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 15).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 5);

            // Assert
            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(3, result.TotalPages);
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(5, result[4]);
        }

        [TestMethod]
        public void Create_LastPartialPage_ReturnsRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 12).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 3, 5);

            // Assert
            Assert.AreEqual(3, result.PageIndex);
            Assert.AreEqual(3, result.TotalPages);
            Assert.AreEqual(2, result.Count);
            Assert.AreEqual(11, result[0]);
            Assert.AreEqual(12, result[1]);
        }
    }
}

