using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            // Drain any leftover notifications from other tests (static queue)
            TestHelper.DrainNotificationQueue();
            _sut = new NotificationService();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            TestHelper.DrainNotificationQueue();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_EnqueuesNotification()
        {
            // Act
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            // Act
            _sut.SendNotification("Course", "42", EntityOperation.UPDATE, "System");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Course (ID: 42) has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DeleteOperation_GeneratesDeleteMessage()
        {
            // Act
            _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithNullUserName_DefaultsToSystem()
        {
            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE, null);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            // Arrange
            var before = DateTime.Now;

            // Act
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "User");

            // Assert
            var after = DateTime.Now;
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
        }

        [TestMethod]
        public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_MultipleMessages_ReturnsFIFOOrder()
        {
            // Arrange
            _sut.SendNotification("A", "1", "First", EntityOperation.CREATE, "User");
            _sut.SendNotification("B", "2", "Second", EntityOperation.UPDATE, "User");
            _sut.SendNotification("C", "3", "Third", EntityOperation.DELETE, "User");

            // Act & Assert
            var first = _sut.ReceiveNotification();
            Assert.AreEqual("A", first.EntityType);

            var second = _sut.ReceiveNotification();
            Assert.AreEqual("B", second.EntityType);

            var third = _sut.ReceiveNotification();
            Assert.AreEqual("C", third.EntityType);

            var empty = _sut.ReceiveNotification();
            Assert.IsNull(empty);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // Act & Assert - MarkAsRead is a no-op for in-memory implementation
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(999);
        }

        [TestMethod]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage()
        {
            // Act
            _sut.SendNotification("Instructor", "7", "Dr. Smith", EntityOperation.CREATE, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.AreEqual("New Instructor 'Dr. Smith' has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            // Act
            _sut.SendNotification("Course", "101", "Physics", EntityOperation.UPDATE, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.AreEqual("Course 'Physics' has been updated", notification.Message);
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            // Act & Assert - should not throw
            _sut.Dispose();
            _sut.Dispose();
        }
    }
}

