using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class HomeControllerTests
    {
        private SchoolContext _context;
        private HomeController _controller;

        [TestInitialize]
        public void Setup()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateSeededContext();
            _controller = new HomeController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
            TestHelper.DrainNotificationQueue();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            // Act
            var result = _controller.Index();

            // Assert
            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void About_ReturnsViewResultWithEnrollmentDateGroups()
        {
            // Act
            var result = _controller.About() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            // We have 3 students with different enrollment dates in seeded data
            Assert.IsTrue(model.Count > 0);
        }

        [TestMethod]
        public void About_ReturnsCorrectStudentCounts()
        {
            // Act
            var result = _controller.About() as ViewResult;

            // Assert
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);

            // Verify the total students across all groups matches the seeded count
            var totalStudents = model.Sum(g => g.StudentCount);
            Assert.AreEqual(3, totalStudents); // 3 students in seeded data
        }

        [TestMethod]
        public void Contact_ReturnsViewResult()
        {
            // Act
            var result = _controller.Contact() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Contact_SetsViewBagMessage()
        {
            // Act
            var result = _controller.Contact() as ViewResult;

            // Assert
            Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
        }

        [TestMethod]
        public void Error_ReturnsViewResult()
        {
            // Act
            var result = _controller.Error();

            // Assert
            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void Unauthorized_ReturnsViewResult()
        {
            // Act
            var result = _controller.Unauthorized() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Unauthorized_SetsViewBagMessage()
        {
            // Act
            _controller.Unauthorized();

            // Assert
            Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }
}

