using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context;
        private StudentsController _controller;

        [TestInitialize]
        public void Setup()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateSeededContext();
            _controller = new StudentsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
            TestHelper.DrainNotificationQueue();
        }

        // ---- Index Tests ----

        [TestMethod]
        public void Index_NoParameters_ReturnsViewWithStudents()
        {
            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count); // 3 seeded students
        }

        [TestMethod]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual("Alexander", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Anand", model[2].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            // Act
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual("Anand", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Alexander", model[2].LastName);
        }

        [TestMethod]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            // Act
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            // Alexander: 2010, Alonso: 2012, Anand: 2013
            Assert.AreEqual("Alexander", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Anand", model[2].LastName);
        }

        [TestMethod]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            // Act
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual("Anand", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Alexander", model[2].LastName);
        }

        [TestMethod]
        public void Index_SearchString_FiltersStudents()
        {
            // Act
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alexander", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchByFirstName_FiltersStudents()
        {
            // Act
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Carson", model[0].FirstMidName);
        }

        [TestMethod]
        public void Index_NewSearchString_ResetsPageToOne()
        {
            // Act
            var result = _controller.Index(null, null, "Al", null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.PageIndex);
        }

        [TestMethod]
        public void Index_SetsViewBagSortParameters()
        {
            // Act
            _controller.Index(null, null, null, null);

            // Assert
            Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
            Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
        }

        [TestMethod]
        public void Index_WithSortOrder_SetsCorrectToggle()
        {
            // Act
            _controller.Index("Date", null, null, null);

            // Assert - Date toggles to date_desc
            Assert.AreEqual("date_desc", _controller.ViewBag.DateSortParm);
        }

        // ---- Details Tests ----

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null);

            // Assert
            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            // Act
            var result = _controller.Details(10) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var student = result.Model as Student;
            Assert.IsNotNull(student);
            Assert.AreEqual("Alexander", student.LastName);
            Assert.AreEqual("Carson", student.FirstMidName);
        }

        // ---- Create GET Tests ----

        [TestMethod]
        public void Create_Get_ReturnsViewWithStudentDefaultDate()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var student = result.Model as Student;
            Assert.IsNotNull(student);
            Assert.AreEqual(DateTime.Today, student.EnrollmentDate);
        }

        // ---- Create POST Tests ----

        [TestMethod]
        public void CreatePost_ValidStudent_RedirectsToIndex()
        {
            // Arrange
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2024-01-15")
            };

            // Act
            var result = _controller.Create(student) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void CreatePost_ValidStudent_AddsToDatabase()
        {
            // Arrange
            var student = new Student
            {
