        [TestMethod]
        public void Delete_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Delete(null);

            // Assert
            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Delete_ValidId_ReturnsViewWithCourse()
        {
            // Act
            var result = _controller.Delete(1050) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
