using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class DepartmentsControllerTests
    {
        private SchoolContext _context;
        private DepartmentsController _controller;

        [TestInitialize]
        public void Setup()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateSeededContext();
            _controller = new DepartmentsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
            TestHelper.DrainNotificationQueue();
        }

        // ---- Index Tests ----

        [TestMethod]
        public void Index_ReturnsViewWithDepartments()
        {
            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as System.Collections.Generic.List<Department>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count); // 2 seeded departments
        }

        // ---- Details Tests ----

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null);

            // Assert
            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            // Act
            var result = _controller.Details(1) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var department = result.Model as Department;
            Assert.IsNotNull(department);
            Assert.AreEqual("English", department.Name);
            Assert.AreEqual(350000m, department.Budget);
        }

        [TestMethod]
        public void Details_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Details(9999);

            // Assert
            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        // ---- Create GET Tests ----

        [TestMethod]
        public void Create_Get_ReturnsView()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        // ---- Create POST Tests ----

        [TestMethod]
        public void CreatePost_ValidDepartment_RedirectsToIndex()
        {
            // Arrange
            var department = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = DateTime.Parse("2024-01-01"),
                InstructorID = 1
            };

            // Act
            var result = _controller.Create(department) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void CreatePost_ValidDepartment_AddsToDatabase()
        {
            // Arrange
            var department = new Department
            {
                Name = "Physics",
                Budget = 250000,
                StartDate = DateTime.Parse("2024-01-01"),
                InstructorID = 1
            };

            // Act
            _controller.Create(department);

            // Assert
            var saved = _context.Departments.FirstOrDefault(d => d.Name == "Physics");
            Assert.IsNotNull(saved);
            Assert.AreEqual(250000m, saved.Budget);
        }

        [TestMethod]
        public void CreatePost_InvalidModelState_ReturnsView()
        {
            // Arrange
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department { Budget = 100000, StartDate = DateTime.Now };

            // Act
            var result = _controller.Create(department) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        // ---- Edit GET Tests ----

        [TestMethod]
        public void Edit_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Edit((int?)null);

            // Assert
            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Edit_ValidId_ReturnsViewWithDepartment()
        {
            // Act
            var result = _controller.Edit((int?)1) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var department = result.Model as Department;
            Assert.IsNotNull(department);
            Assert.AreEqual("English", department.Name);
        }

        [TestMethod]
        public void Edit_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Edit((int?)9999);

            // Assert
            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        // ---- Edit POST Tests ----

        [TestMethod]
        public void EditPost_ValidDepartment_RedirectsToIndex()
        {
            // Arrange
            var department = new Department
            {
                DepartmentID = 1,
                Name = "English Updated",
                Budget = 400000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 1
            };

            // Detach tracked entity
            var tracked = _context.Departments.Find(1);
            _context.Entry(tracked).State = EntityState.Detached;

            // Act
            var result = _controller.Edit(department) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void EditPost_InvalidModelState_ReturnsView()
        {
            // Arrange
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department
            {
                DepartmentID = 1,
                Budget = 100000,
                StartDate = DateTime.Now
            };

            // Act
            var result = _controller.Edit(department) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        // ---- Delete GET Tests ----

        [TestMethod]
        public void Delete_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Delete(null);

            // Assert
            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Delete_ValidId_ReturnsViewWithDepartment()
        {
            // Act
            var result = _controller.Delete(1) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var department = result.Model as Department;
            Assert.IsNotNull(department);
            Assert.AreEqual("English", department.Name);
        }

        [TestMethod]
        public void Delete_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Delete(9999);

            // Assert
            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        // ---- DeleteConfirmed POST Tests ----

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesDepartmentFromDatabase()
        {
            // Act
            _controller.DeleteConfirmed(1);

            // Assert
            var department = _context.Departments.Find(1);
            Assert.IsNull(department);
        }

        [TestMethod]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            // Act
            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void CreatePost_SendsNotification()
        {
            // Arrange
            var department = new Department
            {
                Name = "Biology",
                Budget = 150000,
                StartDate = DateTime.Parse("2024-01-01"),
                InstructorID = 1
            };

            // Act
            _controller.Create(department);

            // Assert - notification was sent
            using var notifService = new ContosoUniversity.Services.NotificationService();
            var notification = notifService.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Department", notification.EntityType);
            Assert.AreEqual("CREATE", notification.Operation);
        }

        [TestMethod]
        public void DeleteConfirmed_SendsNotification()
        {
            // Arrange
            TestHelper.DrainNotificationQueue();

            // Act
            _controller.DeleteConfirmed(2);

            // Assert
            using var notifService = new ContosoUniversity.Services.NotificationService();
            var notification = notifService.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Department", notification.EntityType);
            Assert.AreEqual("DELETE", notification.Operation);
        }
    }
}

