using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class InstructorsControllerTests
    {
        private SchoolContext _context;
        private InstructorsController _controller;

        [TestInitialize]
        public void Setup()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateSeededContext();
            _controller = new InstructorsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
            TestHelper.DrainNotificationQueue();
        }

        // ---- Index Tests ----

        [TestMethod]
        public void Index_NoParameters_ReturnsViewWithInstructors()
        {
            // Act
            var result = _controller.Index(null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Instructors.Count());
        }

        [TestMethod]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            // Act
            var result = _controller.Index(1, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.Courses);
            Assert.AreEqual(1, model.Courses.Count()); // Instructor 1 has 1 course assignment
        }

        [TestMethod]
        public void Index_WithInstructorId_SetsViewBagInstructorID()
        {
            // Act
            _controller.Index(1, null);

            // Assert
            Assert.AreEqual(1, (int)_controller.ViewBag.InstructorID);
        }

        // ---- Details Tests ----

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null);

            // Assert
            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            // Act
            var result = _controller.Details(1) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.IsNotNull(instructor);
            Assert.AreEqual("Abercrombie", instructor.LastName);
            Assert.AreEqual("Kim", instructor.FirstMidName);
        }

        [TestMethod]
        public void Details_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Details(9999);

            // Assert
            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        // ---- Create GET Tests ----

        [TestMethod]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.IsNotNull(instructor);
            Assert.IsNotNull(instructor.CourseAssignments);
            Assert.AreEqual(0, instructor.CourseAssignments.Count);
        }

        // ---- Create POST Tests ----

        [TestMethod]
        public void CreatePost_ValidInstructor_RedirectsToIndex()
        {
            // Arrange
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2024-01-01")
            };

            // Act
            var result = _controller.Create(instructor, null) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void CreatePost_ValidInstructor_AddsToDatabase()
        {
            // Arrange
            var instructor = new Instructor
            {
                LastName = "Smith",
                FirstMidName = "Jane",
                HireDate = DateTime.Parse("2020-06-15")
            };

            // Act
            _controller.Create(instructor, null);

            // Assert
            var saved = _context.Instructors.FirstOrDefault(i => i.LastName == "Smith");
            Assert.IsNotNull(saved);
            Assert.AreEqual("Jane", saved.FirstMidName);
        }

        [TestMethod]
        public void CreatePost_WithSelectedCourses_AssignsCourses()
        {
            // Arrange
            var instructor = new Instructor
            {
                LastName = "CourseInstructor",
                FirstMidName = "Multi",
                HireDate = DateTime.Parse("2024-01-01")
            };
            var selectedCourses = new[] { "1050", "4022" };

            // Act
            _controller.Create(instructor, selectedCourses);

            // Assert
            var saved = _context.Instructors
                .Include(i => i.CourseAssignments)
                .FirstOrDefault(i => i.LastName == "CourseInstructor");
            Assert.IsNotNull(saved);
            Assert.AreEqual(2, saved.CourseAssignments.Count);
        }

        [TestMethod]
        public void CreatePost_InvalidModelState_ReturnsView()
        {
            // Arrange
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2024-01-01")
            };

            // Act
            var result = _controller.Create(instructor, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

