        [TestMethod]
        public void Edit_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Edit((int?)null);

            // Assert
            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Edit_ValidId_ReturnsViewWithInstructor()
        {
            // Act
            var result = _controller.Edit((int?)1) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.IsNotNull(instructor);
            Assert.AreEqual("Abercrombie", instructor.LastName);
        }

        // ---- Delete GET Tests ----

        [TestMethod]
        public void Delete_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Delete(null);

            // Assert
            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Delete_ValidId_ReturnsViewWithInstructor()
        {
            // Act
            var result = _controller.Delete(1) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.IsNotNull(instructor);
            Assert.AreEqual("Abercrombie", instructor.LastName);
        }

        [TestMethod]
        public void Delete_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Delete(9999);

            // Assert
            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        // ---- DeleteConfirmed POST Tests ----

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesInstructorFromDatabase()
        {
            // Arrange - add an instructor with office assignment for the delete path
            var instructor = new Instructor
            {
                ID = 100,
                LastName = "ToDelete",
                FirstMidName = "Delete",
                HireDate = DateTime.Parse("2020-01-01")
            };
            _context.Instructors.Add(instructor);
            _context.OfficeAssignments.Add(new OfficeAssignment
            {
                InstructorID = 100,
                Location = "Room 101"
            });
            _context.SaveChanges();

            // Act
            _controller.DeleteConfirmed(100);

            // Assert
            var result = _context.Instructors.Find(100);
            Assert.IsNull(result);
        }

        [TestMethod]
        public void DeleteConfirmed_InstructorIsDepartmentAdmin_NullsOutDepartmentInstructorID()
        {
            // Arrange - Instructor 1 is administrator of Department 1
            // Act
            _controller.DeleteConfirmed(1);

            // Assert
            var dept = _context.Departments.Find(1);
            Assert.IsNull(dept.InstructorID);
        }

        [TestMethod]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            // Arrange
            var instructor = new Instructor
            {
                ID = 200,
                LastName = "ToDelete2",
                FirstMidName = "Del",
                HireDate = DateTime.Parse("2020-01-01")
            };
            _context.Instructors.Add(instructor);
            _context.OfficeAssignments.Add(new OfficeAssignment
            {
                InstructorID = 200,
                Location = "Room 202"
            });
            _context.SaveChanges();

            // Act
            var result = _controller.DeleteConfirmed(200) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void CreatePost_SendsNotification()
        {
            // Arrange
            TestHelper.DrainNotificationQueue();
            var instructor = new Instructor
            {
                LastName = "NotifTest",
                FirstMidName = "Notif",
                HireDate = DateTime.Parse("2024-01-01")
            };

            // Act
            _controller.Create(instructor, null);

            // Assert
            using var notifService = new ContosoUniversity.Services.NotificationService();
            var notification = notifService.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Instructor", notification.EntityType);
            Assert.AreEqual("CREATE", notification.Operation);
        }
    }
}

