using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        private SchoolContext _context;
        private NotificationsController _controller;

        [TestInitialize]
        public void Setup()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
            TestHelper.DrainNotificationQueue();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            // Act
            var result = _controller.Index();

            // Assert
            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithZeroCount()
        {
            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var jsonResult = result as JsonResult;
            Assert.IsNotNull(jsonResult);
            // Check that the result value contains success = true
            dynamic value = jsonResult.Value;
            Assert.IsNotNull(value);
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Arrange - send some notifications to the queue
            using var notifService = new NotificationService();
            notifService.SendNotification("Student", "1", "John", EntityOperation.CREATE, "Admin");
            notifService.SendNotification("Course", "101", "Math", EntityOperation.UPDATE, "Admin");

            // Act
            var result = _controller.GetNotifications() as JsonResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);
        }

        [TestMethod]
        public void GetNotifications_LimitsToTenNotifications()
        {
            // Arrange - send 15 notifications
            using var notifService = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                notifService.SendNotification("Student", i.ToString(), $"Student{i}", EntityOperation.CREATE, "Admin");
            }

            // Act
            var result = _controller.GetNotifications() as JsonResult;

            // Assert
            Assert.IsNotNull(result);
            // The controller limits to 10 notifications
            Assert.IsNotNull(result.Value);
        }

        [TestMethod]
        public void MarkAsRead_ReturnsJsonResult()
        {
            // Act
            var result = _controller.MarkAsRead(1);

            // Assert
            Assert.IsNotNull(result);
            var jsonResult = result as JsonResult;
            Assert.IsNotNull(jsonResult);
        }

        [TestMethod]
        public void MarkAsRead_ValidId_ReturnsSuccess()
        {
            // Act
            var result = _controller.MarkAsRead(42) as JsonResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);
        }
    }
}

