using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class BaseControllerTests
    {
        private SchoolContext _context;
        private TestableController _controller;

        // Concrete subclass to test abstract BaseController
        private class TestableController : BaseController
        {
            public TestableController(SchoolContext context) : base(context) { }

            public void InvokeSendEntityNotification(string entityType, string entityId, EntityOperation operation)
            {
                SendEntityNotification(entityType, entityId, operation);
            }

            public void InvokeSendEntityNotificationWithName(string entityType, string entityId, string displayName, EntityOperation operation)
            {
                SendEntityNotification(entityType, entityId, displayName, operation);
            }

            public void InvokeDispose()
            {
                Dispose(true);
            }
        }

        [TestInitialize]
        public void Setup()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateInMemoryContext();
            _controller = new TestableController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
            TestHelper.DrainNotificationQueue();
        }

        [TestMethod]
        public void SendEntityNotification_WithoutDisplayName_SendsNotification()
        {
            // Act
            _controller.InvokeSendEntityNotification("Student", "1", EntityOperation.CREATE);

            // Assert
            using var notifService = new NotificationService();
            var notification = notifService.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendEntityNotification_WithDisplayName_SendsNotificationWithName()
        {
            // Act
            _controller.InvokeSendEntityNotificationWithName("Course", "101", "Physics", EntityOperation.UPDATE);

            // Assert
            using var notifService = new NotificationService();
            var notification = notifService.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Course", notification.EntityType);
            Assert.AreEqual("101", notification.EntityId);
            Assert.AreEqual("UPDATE", notification.Operation);
            Assert.AreEqual("Course 'Physics' has been updated", notification.Message);
        }

        [TestMethod]
        public void SendEntityNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            // Act
            _controller.InvokeSendEntityNotificationWithName("Department", "5", "Engineering", EntityOperation.DELETE);

            // Assert
            using var notifService = new NotificationService();
            var notification = notifService.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("DELETE", notification.Operation);
            Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendEntityNotification_WithoutDisplayName_UsesIdInMessage()
        {
            // Act
            _controller.InvokeSendEntityNotification("Instructor", "42", EntityOperation.CREATE);

            // Assert
            using var notifService = new NotificationService();
            var notification = notifService.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("New Instructor (ID: 42) has been created", notification.Message);
        }

        [TestMethod]
        public void Dispose_DisposesContextAndService()
        {
            // Act & Assert - should not throw
            _controller.InvokeDispose();
        }

        [TestMethod]
        public void Constructor_SetsDbContext()
        {
            // Assert
            // The controller should not throw when accessed, confirming context was set
            Assert.IsNotNull(_controller);
        }
    }
}

