using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Data
{
    [TestClass]
    public sealed class SchoolContextTests
    {
        [TestMethod]
        public void SchoolContext_CanAddAndRetrieveStudent()
        {
            // Arrange
            using var context = TestHelper.CreateInMemoryContext();
            var student = new Student
            {
                ID = 1,
                LastName = "TestLast",
                FirstMidName = "TestFirst",
                EnrollmentDate = DateTime.Parse("2024-01-01")
            };

            // Act
            context.Students.Add(student);
            context.SaveChanges();

            // Assert
            var retrieved = context.Students.Find(1);
            Assert.IsNotNull(retrieved);
            Assert.AreEqual("TestLast", retrieved.LastName);
            Assert.AreEqual("TestFirst", retrieved.FirstMidName);
        }

        [TestMethod]
        public void SchoolContext_CanAddAndRetrieveCourse()
        {
            // Arrange
            using var context = TestHelper.CreateInMemoryContext();
            var course = new Course
            {
                CourseID = 1001,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 0
            };

            // Act
            context.Courses.Add(course);
            context.SaveChanges();

            // Assert
            var retrieved = context.Courses.Find(1001);
            Assert.IsNotNull(retrieved);
            Assert.AreEqual("Test Course", retrieved.Title);
            Assert.AreEqual(3, retrieved.Credits);
        }

        [TestMethod]
        public void SchoolContext_CanAddAndRetrieveDepartment()
        {
            // Arrange
            using var context = TestHelper.CreateInMemoryContext();
            var department = new Department
            {
                DepartmentID = 1,
                Name = "Science",
                Budget = 500000m,
                StartDate = DateTime.Parse("2020-01-01")
            };

            // Act
            context.Departments.Add(department);
            context.SaveChanges();

            // Assert
            var retrieved = context.Departments.Find(1);
            Assert.IsNotNull(retrieved);
            Assert.AreEqual("Science", retrieved.Name);
            Assert.AreEqual(500000m, retrieved.Budget);
        }

        [TestMethod]
        public void SchoolContext_CanAddAndRetrieveInstructor()
        {
            // Arrange
            using var context = TestHelper.CreateInMemoryContext();
            var instructor = new Instructor
            {
                ID = 1,
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = DateTime.Parse("2000-01-01")
            };

            // Act
            context.Instructors.Add(instructor);
            context.SaveChanges();

            // Assert
            var retrieved = context.Instructors.Find(1);
            Assert.IsNotNull(retrieved);
            Assert.AreEqual("Smith", retrieved.LastName);
            Assert.AreEqual(DateTime.Parse("2000-01-01"), retrieved.HireDate);
        }

        [TestMethod]
        public void SchoolContext_CourseAssignment_CompositeKey()
        {
            // Arrange
            using var context = TestHelper.CreateInMemoryContext();
            var instructor = new Instructor
            {
                ID = 1,
                LastName = "Inst",
                FirstMidName = "A",
                HireDate = DateTime.Parse("2000-01-01")
            };
            var course = new Course
            {
                CourseID = 100,
                Title = "TestCourse",
                Credits = 3,
                DepartmentID = 0
            };
            context.Instructors.Add(instructor);
            context.Courses.Add(course);
            context.SaveChanges();

            var assignment = new CourseAssignment
            {
                CourseID = 100,
                InstructorID = 1
            };

            // Act
            context.CourseAssignments.Add(assignment);
            context.SaveChanges();

            // Assert
            var retrieved = context.CourseAssignments.Find(100, 1);
            Assert.IsNotNull(retrieved);
            Assert.AreEqual(100, retrieved.CourseID);
            Assert.AreEqual(1, retrieved.InstructorID);
        }

        [TestMethod]
        public void SchoolContext_OfficeAssignment_OneToOne()
        {
            // Arrange
            using var context = TestHelper.CreateInMemoryContext();
            var instructor = new Instructor
            {
                ID = 1,
                LastName = "Office",
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2000-01-01")
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var office = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Room 101"
            };

            // Act
            context.OfficeAssignments.Add(office);
            context.SaveChanges();

            // Assert
