using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Models
{
    [TestClass]
    public sealed class ModelPropertyTests
    {
        // ---- Course Model Tests ----

        [TestMethod]
        public void Course_Properties_SetAndGetCorrectly()
        {
            // Arrange & Act
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/uploads/chem.jpg"
            };

            // Assert
            Assert.AreEqual(1050, course.CourseID);
            Assert.AreEqual("Chemistry", course.Title);
            Assert.AreEqual(3, course.Credits);
            Assert.AreEqual(1, course.DepartmentID);
            Assert.AreEqual("/uploads/chem.jpg", course.TeachingMaterialImagePath);
        }

        [TestMethod]
        public void Course_NavigationProperties_CanBeSetToNull()
        {
            // Arrange
            var course = new Course();

            // Assert
            Assert.IsNull(course.Department);
            Assert.IsNull(course.Enrollments);
            Assert.IsNull(course.CourseAssignments);
        }

        [TestMethod]
        public void Course_NavigationProperties_CanBePopulated()
        {
            // Arrange
            var course = new Course
            {
                Enrollments = new List<Enrollment> { new Enrollment() },
                CourseAssignments = new List<CourseAssignment> { new CourseAssignment() }
            };

            // Assert
            Assert.AreEqual(1, course.Enrollments.Count);
            Assert.AreEqual(1, course.CourseAssignments.Count);
        }

        // ---- Department Model Tests ----

        [TestMethod]
        public void Department_Properties_SetAndGetCorrectly()
        {
            // Arrange & Act
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "English",
                Budget = 350000m,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 5,
                RowVersion = new byte[] { 0x01, 0x02 }
            };

            // Assert
            Assert.AreEqual(1, dept.DepartmentID);
            Assert.AreEqual("English", dept.Name);
            Assert.AreEqual(350000m, dept.Budget);
            Assert.AreEqual(DateTime.Parse("2007-09-01"), dept.StartDate);
            Assert.AreEqual(5, dept.InstructorID);
            Assert.AreEqual(2, dept.RowVersion.Length);
        }

        [TestMethod]
        public void Department_InstructorID_IsNullable()
        {
            // Arrange
            var dept = new Department { InstructorID = null };

            // Assert
            Assert.IsNull(dept.InstructorID);
        }

        // ---- Enrollment Model Tests ----

        [TestMethod]
        public void Enrollment_Properties_SetAndGetCorrectly()
        {
            // Arrange & Act
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 10,
                Grade = Grade.A
            };

            // Assert
            Assert.AreEqual(1, enrollment.EnrollmentID);
            Assert.AreEqual(1050, enrollment.CourseID);
            Assert.AreEqual(10, enrollment.StudentID);
            Assert.AreEqual(Grade.A, enrollment.Grade);
        }

        [TestMethod]
        public void Enrollment_Grade_IsNullable()
        {
            // Arrange
            var enrollment = new Enrollment { Grade = null };

            // Assert
            Assert.IsNull(enrollment.Grade);
        }

        [TestMethod]
        [DataRow(Grade.A, DisplayName = "Grade A")]
        [DataRow(Grade.B, DisplayName = "Grade B")]
        [DataRow(Grade.C, DisplayName = "Grade C")]
        [DataRow(Grade.D, DisplayName = "Grade D")]
        [DataRow(Grade.F, DisplayName = "Grade F")]
        public void Enrollment_AllGradeValues_CanBeAssigned(Grade grade)
        {
            // Arrange & Act
            var enrollment = new Enrollment { Grade = grade };

            // Assert
            Assert.AreEqual(grade, enrollment.Grade);
        }

        // ---- CourseAssignment Model Tests ----

        [TestMethod]
        public void CourseAssignment_Properties_SetAndGetCorrectly()
        {
            // Arrange & Act
            var assignment = new CourseAssignment
            {
                InstructorID = 1,
